var assert = require('assert');
var Hemera = require('../lib/hemera');

describe('Hemera', function() {
    it('should return a function', function() {
        var hemera = new Hemera();
        assert(typeof hemera == 'object');
        assert(typeof hemera.getMovies == 'function');
    });
    
    it('should passed', function(done) {
        this.timeout(10000);
        var hemera = new Hemera();

        hemera.search({q: 'sss', tag: '剧情'} ,function(body) {
            body = JSON.parse(body);
            
            setTimeout(done, 4000);
        });

    });

});
